### useStdin() - Access Stdin Stream and Raw Mode in Ink

Source: https://context7.com/vadimdemedes/ink/llms.txt

The useStdin hook exposes the stdin stream and a setRawMode function, which is essential for capturing special key combinations like Ctrl+C. This hook allows for interactive command-line applications.

```javascript
import React, {useEffect} from 'react';
import {render, useStdin, Box, Text} from 'ink';

function StdinExample() {
  const {stdin, setRawMode, isRawModeSupported} = useStdin();

  useEffect(() => {
    if (!isRawModeSupported) return;

    setRawMode(true);

    const handler = (data) => {
      console.log('Raw data:', Buffer.from(data).toString('hex'));
    };

    stdin.on('data', handler);

    return () => {
      stdin.removeListener('data', handler);
      setRawMode(false);
    };
  }, []);

  return (
    <Box>
      <Text>
        Raw mode: {isRawModeSupported ? 'Supported' : 'Not supported'}
      </Text>
    </Box>
  );
}

render(<StdinExample />);

```

