### Enable Component Focus Management with useFocus Hook (Ink)

Source: https://context7.com/vadimdemedes/ink/llms.txt

The useFocus hook makes Ink components focusable, returning an `isFocused` boolean and a `focus` function. It integrates with keyboard navigation (Tab/Shift+Tab) to cycle through focusable elements in their render order.

```javascript
import React, {useState} from 'react';
import {render, useFocus, useInput, Box, Text} from 'ink';

function FocusableInput({label, autoFocus = false}) {
  const {isFocused} = useFocus({autoFocus});
  const [value, setValue] = useState('');

  useInput((input, key) => {
    if (!isFocused) return;

    if (key.backspace) {
      setValue(v => v.slice(0, -1));
    } else if (input && !key.ctrl && !key.meta) {
      setValue(v => v + input);
    }
  });

  return (
    <Box>
      <Text color={isFocused ? 'cyan' : 'white'}>
        {isFocused ? '> ' : '  '}
        {label}: {value}
        {isFocused ? '█' : ''}
      </Text>
    </Box>
  );
}

function Form() {
  return (
    <Box flexDirection="column">
      <Text bold>Fill out the form (Tab to switch fields):</Text>
      <FocusableInput label="Name" autoFocus />
      <FocusableInput label="Email" />
      <FocusableInput label="Phone" />
    </Box>
  );
}

render(<Form />);
```

